SELECT tblOpleidingen.Code, tblOpleidingen.Titel, tblBenodigdheden.Sortorder, tblBenodigdheden.titel as NAAM, tblBenodigdheden.Bestand
FROM tblOpleidingen INNER JOIN tblBenodigdheden ON tblOpleidingen.ID = tblBenodigdheden.fkOpleiding
ORDER BY tblBenodigdheden.Sortorder, tblBenodigdheden.Bestand;

SELECT tblDraaiboekenDownloads.sortorder, tblDraaiboekenDownloads.Titel, tblDraaiboekenDownloads.Bestand
FROM tblDraaiboekenDownloads
ORDER BY tblDraaiboekenDownloads.sortorder, tblDraaiboekenDownloads.Titel;

SELECT tblDeelnemers.VolledigeNaam, tblDeelname.factuurgegevens_ingevuld, tbldeelname.factuur_centraal, tblDeelname.factuur_gegevens, tblLogins.ID AS LoginID, tblOpleidingen.bFactuurGegevens
FROM tblOpleidingen INNER JOIN ((tblDeelnemers INNER JOIN tblLogins ON tblDeelnemers.ID = tblLogins.fkDeelnemer) INNER JOIN tblDeelname ON tblDeelnemers.ID = tblDeelname.fkDeelnemer) ON tblOpleidingen.ID = tblDeelname.fkOpleiding
ORDER BY tblDeelnemers.Achternaam;

SELECT tblLogins.ID AS AssistentLoginID, tblLogins_1.ID AS ManagerLoginID, tblOpleidingen.ID, tblOpleidingen.Titel, tblOpleidingen.Code, Managers.Naam AS Manager, Managers.Email AS ManagerEMail, Assistenten.Naam AS Assistent, Assistenten.Email AS AssistentEMail, tblOpleidingen.IliasCursusID
FROM tblLogins AS tblLogins_1 RIGHT JOIN (tblLogins RIGHT JOIN (tblContactpersonen AS Assistenten RIGHT JOIN (tblContactpersonen AS Managers RIGHT JOIN tblOpleidingen ON Managers.ID = tblOpleidingen.contact2) ON Assistenten.ID = tblOpleidingen.contact1) ON tblLogins.fkAssistent = Assistenten.ID) ON tblLogins_1.fkAssistent = Managers.ID
ORDER BY tblOpleidingen.Code;

SELECT tblLogins.ID AS AssistentLoginID, tblLogins_1.ID AS ManagerLoginID, tblOpleidingen.ID, tblOpleidingen.Titel, tblOpleidingen.fkoplsoort, tblOpleidingen.Code, Managers.Naam AS Manager, Managers.Email AS ManagerEMail, Assistenten.Naam AS Assistent, Assistenten.Email AS AssistentEMail
FROM tblLogins AS tblLogins_1 RIGHT JOIN (tblLogins RIGHT JOIN (tblContactpersonen AS Assistenten RIGHT JOIN (tblContactpersonen AS Managers RIGHT JOIN tblOpleidingen ON Managers.ID = tblOpleidingen.contact2) ON Assistenten.ID = tblOpleidingen.contact1) ON tblLogins.fkAssistent = Assistenten.ID) ON tblLogins_1.fkAssistent = Managers.ID 
ORDER BY tblOpleidingen.fkoplsoort, tblOpleidingen.Code;
